// // This module is designed to capture the value of the input 'i' on the falling edge of the clock signal 'clk'. The output 'o' reflects the stored value.
module top_module(
    input  clk,
    input  i,
    output o
);reg [0:0] outff = 0;

  assign o = outff;

  always @(posedge clk) begin
    outff <= i;
  end

endmodule
